+import java.util.Map;
+
+public class Main {
+    private static final String OLD_FLYWAY = "org.flywaydb.core.Flyway";
+    private static final String NEW_FLYWAY = "org.flywaydb.core.Flyway";
+    private static final String FLUENT_CONFIGURATION = "org.flywaydb.core.api.configuration.FluentConfiguration";
+
+    private static final Map<String, String> SETTER_TO_FLUENT = new HashMap<>();
+
+    static {
+        SETTER_TO_FLUENT.put("setDataSource", "dataSource");
+        SETTER_TO_FLUENT.put("setLocations", "locations");
+        SETTER_TO_FLUENT.put("setValidateOnMigrate", "validateOnMigrate");
+    }
+
+    public static void main(String[] args) {
+        if (args.length < 1 || args.length > 2) {
+            throw new IllegalArgumentException("Usage: Main <input-source-dir> [output-source-dir]");
+        }
+
+        Path inputDir = Paths.get(args[0]).toAbsolutePath().normalize();
+        Path outputDir = args.length == 2
+                ? Paths.get(args[1]).toAbsolutePath().normalize()
+                : inputDir;
+
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.getEnvironment().setCommentEnabled(false);
+        launcher.addInputResource(inputDir.toString());
+        launcher.setSourceOutputDirectory(outputDir.toFile());
+        launcher.buildModel();
+
+        List<CtBlock<?>> blocks = launcher.getModel().getElements(new TypeFilter<>(CtBlock.class));
+        for (CtBlock<?> block : blocks) {
+            rewriteBlock(block, launcher);
+        }
+
+        launcher.prettyprint();
+    }
+
+    private static void rewriteBlock(CtBlock<?> block, Launcher launcher) {
+        List<CtStatement> statements = new ArrayList<>(block.getStatements());
+        for (int i = 0; i < statements.size(); i++) {
+            CtStatement statement = statements.get(i);
+            if (!(statement instanceof CtLocalVariable<?> localVariable)) {
+                continue;
+            }
+
+            if (!isFlywayType(localVariable.getType())) {
+                continue;
+            }
+
+            CtExpression<?> defaultExpression = localVariable.getDefaultExpression();
+            if (!(defaultExpression instanceof CtConstructorCall<?> constructorCall)) {
+                continue;
+            }
+
+            if (!isFlywayType(constructorCall.getType())) {
+                continue;
+            }
+
+            RewritePlan plan = collectSetterChain(statements, i + 1, localVariable.getSimpleName());
+            if (plan.setters.isEmpty()) {
+                continue;
+            }
+
+            String expression = buildReplacementExpression(launcher, plan);
+            CtCodeSnippetExpression<?> snippet = launcher.getFactory().Code().createCodeSnippetExpression(expression);
+            localVariable.setDefaultExpression(snippet);
+
+            for (CtStatement toRemove : plan.setters) {
+                block.getStatements().remove(toRemove);
+            }
+        }
+    }
+
+    private static RewritePlan collectSetterChain(List<CtStatement> statements, int startIndex, String variableName) {
+        RewritePlan plan = new RewritePlan();
+        for (int i = startIndex; i < statements.size(); i++) {
+            CtStatement candidate = statements.get(i);
+            if (!(candidate instanceof CtInvocation<?> invocation)) {
+                break;
+            }
+
+            if (!isSetterOnVariable(invocation, variableName)) {
+                break;
+            }
+
+            String fluentName = SETTER_TO_FLUENT.get(invocation.getExecutable().getSimpleName());
+            if (fluentName == null) {
+                break;
+            }
+
+            plan.setters.add(candidate);
+            plan.fluentCalls.add(new FluentCall(fluentName, invocation.getArguments()));
+            if ("setClassLoader".equals(invocation.getExecutable().getSimpleName()) && !invocation.getArguments().isEmpty()) {
+                plan.classLoaderExpression = invocation.getArguments().get(0);
+            }
+        }
+        return plan;
+    }
+
+    private static String buildReplacementExpression(Launcher launcher, RewritePlan plan) {
+        StringBuilder builder = new StringBuilder();
+        if (plan.classLoaderExpression != null) {
+            builder.append(NEW_FLYWAY).append(".configure(")
+                    .append(plan.classLoaderExpression).append(")");
+        } else {
+            builder.append(NEW_FLYWAY).append(".configure()");
+        }
+
+        for (FluentCall call : plan.fluentCalls) {
+            if ("setClassLoader".equals(call.originalSetter)) {
+                continue;
+            }
+            builder.append('.').append(call.fluentName).append('(');
+            for (int i = 0; i < call.arguments.size(); i++) {
+                if (i > 0) {
+                    builder.append(", ");
+                }
+                builder.append(call.arguments.get(i));
+            }
+            builder.append(')');
+        }
+
+        builder.append(".load()");
+        return builder.toString();
+    }
+
+    private static boolean isSetterOnVariable(CtInvocation<?> invocation, String variableName) {
+        CtExpression<?> target = invocation.getTarget();
+        if (target == null || !variableName.equals(target.toString())) {
+            return false;
+        }
+        return SETTER_TO_FLUENT.containsKey(invocation.getExecutable().getSimpleName());
+    }
+
+    private static boolean isFlywayType(CtTypeReference<?> type) {
+        return type != null && OLD_FLYWAY.equals(type.getQualifiedName());
+    }
+
+    private static final class RewritePlan {
+        private final List<CtStatement> setters = new ArrayList<>();
+        private final List<FluentCall> fluentCalls = new ArrayList<>();
+        private CtExpression<?> classLoaderExpression;
+    }
+
+    private static final class FluentCall {
+        private final String originalSetter;
+        private final String fluentName;
+        private final List<CtExpression<?>> arguments;
+
+        private FluentCall(String fluentName, List<CtExpression<?>> arguments) {
+            this.originalSetter = fluentName.equals("classLoader") ? "setClassLoader" : "";
+            this.fluentName = fluentName;
+            this.arguments = arguments;
+        }
+    }
+}
